# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

import java.io.File
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Paths, Path, Files}

class FileController extends Controller {
  private val baseDirectory = "uploads"
  
  def serveFile(filename: String) = Action {
    try {
      val canonicalBase = new File(baseDirectory).getCanonicalFile
      val filePath = Paths.get(baseDirectory, filename).normalize()
      val resolvedPath = filePath.toFile.getCanonicalFile
      
      if (!resolvedPath.getAbsolutePath.startsWith(canonicalBase.getAbsolutePath)) {
        return NotFound(views.html.error("Invalid file path"))
      }
      
      if (!Files.exists(filePath) || Files.isDirectory(filePath)) {
        return NotFound(views.html.error("File not found"))
      }
      
      val source = Source.fromFile(resolvedPath.getAbsolutePath)
      val content = source.mkString
      source.close()
      
      Ok(content).withHeaders("Content-Type" -> "text/plain")
    } catch {
      case _: Exception => NotFound(views.html.error("File not found"))
    }
  }
}